const jobIds = await hound.emitBatch([
  { event: 'email.send', data: { to: 'alice@example.com' } },
  { event: 'email.send', data: { to: 'bob@example.com' } },
  { event: 'analytics.track', data: { event: 'signup' }, options: { queue: 'analytics' } },
]);
console.log(jobIds); // ['abc...', 'def...', 'ghi...']

const result = await hound.emitAndWait(
  'report.generate',
  { reportId: 'q4-2024' },
  { timeoutMs: 60_000 }
);
console.log(result.status); // 'completed'

// Schedule a job for tomorrow
hound.emit('report.weekly', {}, {
  delay: new Date(Date.now() + 86_400_000),
  attempts: 3,
  retryBackoff: 'exponential',
});

// Idempotent emit with a fixed ID
await hound.emitAsync('invoice.send', { invoiceId: 'INV-001' }, {
  id: 'invoice-INV-001',
});
